import React, { useRef, useState, useMemo } from "react";
import "./GelirEkleme.css";

export default function GelirEkleme() {
    const inputRef = useRef(null);
    const [isDragging, setIsDragging] = useState(false);
    const [file, setFile] = useState(null);
    const [error, setError] = useState("");

    const allowed = useMemo(() => [".xlsx", ".xls", ".csv"], []);

    const openPicker = () => inputRef.current?.click();

    const onFilePicked = (e) => {
        const f = e.target.files?.[0];
        if (!f) return;
        validateAndSet(f);
    };

    const onDrop = (e) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(false);
        const f = e.dataTransfer.files?.[0];
        if (!f) return;
        validateAndSet(f);
    };

    const validateAndSet = (f) => {
        const ok = allowed.some((ext) => f.name.toLowerCase().endsWith(ext));
        if (!ok) {
            setError("L�tfen .xlsx, .xls veya .csv uzant�l� bir dosya y�kleyin.");
            setFile(null);
            return;
        }
        setError("");
        setFile(f);
    };

    const onDragOver = (e) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(true);
    };

    const onDragLeave = (e) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(false);
    };

    const reset = () => {
        setFile(null);
        setError("");
        if (inputRef.current) inputRef.current.value = "";
    };

    const formatSize = (bytes) => {
        if (bytes < 1024) return `${bytes} B`;
        if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
        return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
    };

    // Basit CSV �ablonu indir
    const downloadTemplate = () => {
        const headers = ["Tarih (YYYY-MM-DD)", "Kategori", "Tutar", "A��klama"];
        const sample = [
            "2025-01-15", "Sat��", "12500.00", "Ocak online sat�� geliri"
        ];
        const csv = [headers.join(","), sample.map(v => `"${String(v).replaceAll('"', '""')}"`).join(",")].join("\n");
        const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = "gelir_sablon.csv";
        a.click();
        URL.revokeObjectURL(url);
    };

    const upload = () => {
        if (!file) return;
        // Burada API'ye yollayabilirsin (FormData ile)
        // const fd = new FormData(); fd.append("file", file);
        // await fetch("/api/gelir-yukle", { method: "POST", body: fd });

        alert(`Y�klendi: ${file.name}`);
        reset();
    };

    return (
        <div className="ge-page">
            {/* �st bar */}
            <div className="ge-topbar">
                <div>
                    <h1>Gelir Ekleme</h1>
                    <p className="ge-sub">Excel/CSV ile toplu y�kleme yap veya tek dosya s�r�kle-b�rak.</p>
                </div>
                <div className="ge-top-actions">
                    <button className="btn ghost" onClick={downloadTemplate}>�ablonu �ndir</button>
                    <button className="btn" onClick={openPicker}>Dosya Se�</button>
                    <input
                        ref={inputRef}
                        type="file"
                        accept={allowed.join(",")}
                        onChange={onFilePicked}
                        hidden
                    />
                </div>
            </div>

            {/* Drop zone */}
            <div
                className={`ge-drop ${isDragging ? "dragging" : ""}`}
                onDragOver={onDragOver}
                onDragLeave={onDragLeave}
                onDrop={onDrop}
                onClick={openPicker}
                role="button"
                tabIndex={0}
            >
                <div className="ge-drop-inner">
                    <div className="ge-icon">??</div>
                    <div className="ge-title">Dosyan� buraya s�r�kle & b�rak</div>
                    <div className="ge-muted">veya <span className="ge-link">bilgisayardan se�</span> (.xlsx, .xls, .csv)</div>
                </div>
            </div>

            {/* Se�ilen dosya kart� */}
            {file && (
                <div className="ge-file">
                    <div className="ge-file-main">
                        <div className="ge-file-icon">??</div>
                        <div>
                            <div className="ge-file-name">{file.name}</div>
                            <div className="ge-file-meta">{formatSize(file.size)}</div>
                        </div>
                    </div>
                    <button className="btn ghost danger" onClick={reset}>Kald�r</button>
                </div>
            )}

            {/* Hata */}
            {error && <div className="ge-error">{error}</div>}

            {/* Alt aksiyon bar� */}
            <div className="ge-bottombar">
                <div className="ge-bottombar-left">
                    {file ? <span>Y�klemeye haz�r: <strong>{file.name}</strong></span> : <span>Hen�z dosya se�ilmedi</span>}
                </div>
                <div className="ge-bottombar-actions">
                    <button className="btn ghost" onClick={reset} disabled={!file}>Temizle</button>
                    <button className="btn primary" onClick={upload} disabled={!file}>Y�kle</button>
                </div>
            </div>
        </div>
    );
}
